import React from "react";
import Layout from "../../layout";
import ProductDetails from "../../product-details";
import { useParams } from "react-router-dom";
import productsData from "../../homepage/product-listing/product.json";

interface ProductProps {
  id: number;
  name: string;
  price: number;
  img: string;
}

const ProductPage:React.FC<ProductProps> = () => {

  const {productId} = useParams()
  // const thisProduct = productsData.find(prod => prod.id === productId)
  const thisProduct: ProductProps | undefined = productsData.find(
    (prod: ProductProps) => prod.id === Number(productId)
  );

  if (!thisProduct) {
    // Handle the case where the product is not found
    return <div>Product not found</div>;
  }


  return (
    <Layout>
      <ProductDetails />
    </Layout>
  );
};

export default ProductPage;

